// Temporal clustering logic
// Assigns each entry to a timeline_group based on date_estimated
//
// Customize the date ranges and group names for your project.
// Current groups match a 3-era narrative structure:
//   1974-1990 — Origin/founding period
//   2019-2023 — Exploration/growth period
//   2024-2026 — Current/integration period

const entries = $input.all();
const clustered = [];

for (const item of entries) {
  const entry = item.json;
  let timeline_group = '2024-2026'; // default to current period

  // Parse date_estimated field
  const dateStr = entry.date_estimated || '';

  if (dateStr) {
    let year = null;

    // Handle YYYY format
    if (/^\d{4}$/.test(dateStr)) {
      year = parseInt(dateStr);
    }
    // Handle YYYY-MM-DD format
    else if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
      year = parseInt(dateStr.split('-')[0]);
    }
    // Handle any other format — extract 4-digit year
    else {
      const match = dateStr.match(/\d{4}/);
      if (match) year = parseInt(match[0]);
    }

    // Map year to timeline_group
    // CUSTOMIZE: Change these ranges to match your project's history
    if (year) {
      if (year >= 1974 && year <= 1990) {
        timeline_group = '1974-1990';
      } else if (year >= 2019 && year <= 2023) {
        timeline_group = '2019-2023';
      } else if (year >= 2024 && year <= 2026) {
        timeline_group = '2024-2026';
      }
    }
  }

  clustered.push({
    json: {
      id: entry.id,
      file_name: entry.file_name,
      timeline_group: timeline_group,
      date_estimated: entry.date_estimated,
      narrative_role: entry.narrative_role
    }
  });
}

return clustered;

// Narrative arc detection
// Groups entries by timeline period and identifies dominant narrative roles
//
// narrative_role values follow a story arc:
// setup → origin → exploration → conflict → realisation → integration
//
// CUSTOMIZE: Change the expected narrative roles to match your taxonomy.

const items = $input.all();

// Group by timeline_group
const groups = {
  '1974-1990': [],
  '2019-2023': [],
  '2024-2026': []
};

for (const item of items) {
  const group = item.json.timeline_group;
  if (groups[group]) {
    groups[group].push(item.json);
  }
}

// Analyze narrative arc for each period
const analysis = {
  '1974-1990': {
    count: groups['1974-1990'].length,
    roles: groups['1974-1990'].map(e => e.narrative_role).filter(Boolean),
    dominant: 'origin'
  },
  '2019-2023': {
    count: groups['2019-2023'].length,
    roles: groups['2019-2023'].map(e => e.narrative_role).filter(Boolean),
    dominant: 'exploration'
  },
  '2024-2026': {
    count: groups['2024-2026'].length,
    roles: groups['2024-2026'].map(e => e.narrative_role).filter(Boolean),
    dominant: 'integration'
  }
};

return [{"json": {"analysis": analysis, "total_entries": items.length, "entries_to_update": items}}];

const batch = $input.item.json;
